package update

import (
	"context"
	"fmt"
	"os"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// Checker handles update checking logic
type Checker struct {
	currentVersion string
	config         *config.NewConfig
	cache          *Cache
	result         *UpdateCheckResult
}

// NewChecker creates a new Checker instance
func NewChecker(version string, cfg *config.NewConfig) *Checker {
	cache := NewCache()
	// Try to load cache, but don't fail if it doesn't exist
	_ = cache.Load()

	return &Checker{
		currentVersion: version,
		config:         cfg,
		cache:          cache,
	}
}

// ShouldCheck returns true if an update check is needed
func (c *Checker) ShouldCheck() bool {
	// Check if disabled in config
	if c.config.UpdateCheck != nil && !c.config.UpdateCheck.Enabled {
		return false
	}

	// Check if cache is expired or missing
	if c.cache.IsExpired() {
		return true
	}

	// Check if version changed (binary was upgraded)
	if c.cache.data.CurrentVersion != "" && c.cache.data.CurrentVersion != c.currentVersion {
		return true
	}

	// Cache is valid and fresh
	return false
}

// CheckForUpdate performs an update check if needed
// Returns the result, which is also stored in c.result for later retrieval
func (c *Checker) CheckForUpdate(ctx context.Context) (*UpdateCheckResult, error) {
	// Check if disabled via env var (takes precedence)
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		c.result = &UpdateCheckResult{
			UpdateAvailable: false,
			LatestVersion:   c.currentVersion,
			Error:           nil,
		}
		return c.result, nil
	}

	// If check not needed, return cached result — but re-verify the cached
	// answer is still valid for the current binary version. If the user
	// upgraded past the cached LatestVersion, the cache is stale.
	if !c.ShouldCheck() {
		updateAvailable := c.cache.data.UpdateAvailable
		if updateAvailable && c.cache.data.LatestVersion != "" {
			needsUpgrade, err := NeedsUpgrade(c.currentVersion, c.cache.data.LatestVersion)
			if err != nil || !needsUpgrade {
				updateAvailable = false
			}
		}
		c.result = &UpdateCheckResult{
			UpdateAvailable: updateAvailable,
			LatestVersion:   c.cache.data.LatestVersion,
			Error:           nil,
		}
		return c.result, nil
	}

	// Perform actual check
	result := &UpdateCheckResult{}

	// Fetch latest release from GitHub
	release, err := FetchLatestRelease()
	if err != nil {
		result.Error = fmt.Errorf("failed to fetch latest release: %w", err)
		c.result = result

		// Update cache with error
		c.cache.data.LastCheck = time.Now()
		c.cache.data.CurrentVersion = c.currentVersion
		c.cache.data.CheckError = err.Error()
		_ = c.cache.Save() // Ignore save errors

		return result, err
	}

	// Compare versions
	needsUpgrade, err := NeedsUpgrade(c.currentVersion, release.TagName)
	if err != nil {
		result.Error = fmt.Errorf("failed to compare versions: %w", err)
		c.result = result

		// Update cache with error
		c.cache.data.LastCheck = time.Now()
		c.cache.data.CurrentVersion = c.currentVersion
		c.cache.data.CheckError = err.Error()
		_ = c.cache.Save() // Ignore save errors

		return result, err
	}

	// Update result
	result.UpdateAvailable = needsUpgrade
	result.LatestVersion = release.TagName
	c.result = result

	// Update cache with successful check
	c.cache.data.LastCheck = time.Now()
	c.cache.data.CurrentVersion = c.currentVersion
	c.cache.data.LatestVersion = release.TagName
	c.cache.data.UpdateAvailable = needsUpgrade
	c.cache.data.CheckError = ""

	_ = c.cache.Save() // Ignore save errors

	return result, nil
}

// IsUpdateAvailable returns the result from the last check
func (c *Checker) IsUpdateAvailable() (bool, string, error) {
	if c.result == nil {
		return false, "", nil
	}
	return c.result.UpdateAvailable, c.result.LatestVersion, c.result.Error
}

package cmd

import (
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"

	"github.com/DocumentDrivenDX/ddx/internal/update"
	"github.com/fatih/color"
	"github.com/spf13/cobra"
)

const (
	installScriptURL = "https://raw.githubusercontent.com/DocumentDrivenDX/ddx/main/install.sh"
)

func (f *CommandFactory) runUpgrade(cmd *cobra.Command, args []string) error {
	checkOnly, _ := cmd.Flags().GetBool("check")
	force, _ := cmd.Flags().GetBool("force")

	cyan := color.New(color.FgCyan)
	green := color.New(color.FgGreen)
	yellow := color.New(color.FgYellow)

	out := cmd.OutOrStdout()

	_, _ = cyan.Fprintln(out, "🔍 Checking for DDx updates...")
	_, _ = fmt.Fprintln(out)

	// Get current version
	currentVersion := f.Version
	if currentVersion == "" || currentVersion == "dev" {
		currentVersion = "v0.0.1-dev"
	}

	// Fetch latest release from GitHub
	latestRelease, err := update.FetchLatestRelease()
	if err != nil {
		return fmt.Errorf("failed to check for updates: %w", err)
	}

	latestVersion := latestRelease.TagName

	// Display current and latest versions
	_, _ = fmt.Fprintf(out, "Current version: %s\n", currentVersion)
	_, _ = fmt.Fprintf(out, "Latest version:  %s\n", latestVersion)
	_, _ = fmt.Fprintln(out)

	// Compare versions
	needsUpgrade, err := update.NeedsUpgrade(currentVersion, latestVersion)
	if err != nil && !force {
		return fmt.Errorf("failed to compare versions: %w", err)
	}

	if !needsUpgrade && !force {
		_, _ = green.Fprintln(out, "✅ You are already running the latest version of DDx!")
		return nil
	}

	if checkOnly {
		if needsUpgrade {
			_, _ = yellow.Fprintln(out, "⬆️  A new version of DDx is available!")
			_, _ = fmt.Fprintln(out)
			_, _ = fmt.Fprintln(out, "To upgrade, run:")
			_, _ = green.Fprintln(out, "  ddx upgrade")
		}
		return nil
	}

	// Perform upgrade
	if force {
		_, _ = yellow.Fprintf(out, "⚠️  Force upgrading to %s...\n", latestVersion)
	} else {
		_, _ = cyan.Fprintf(out, "⬆️  Upgrading DDx from %s to %s...\n", currentVersion, latestVersion)
	}
	_, _ = fmt.Fprintln(out)

	// Download and execute install script
	if err := executeUpgrade(out); err != nil {
		return fmt.Errorf("upgrade failed: %w", err)
	}

	_, _ = fmt.Fprintln(out)
	_, _ = green.Fprintln(out, "✅ DDx has been upgraded successfully!")
	_, _ = fmt.Fprintln(out)
	_, _ = fmt.Fprintln(out, "Run 'ddx version' to verify the new version.")

	return nil
}

// executeUpgrade downloads and executes the install script
func executeUpgrade(out io.Writer) error {
	// Download install script
	resp, err := http.Get(installScriptURL)
	if err != nil {
		return fmt.Errorf("failed to download install script: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("failed to download install script: status %d", resp.StatusCode)
	}

	scriptContent, err := io.ReadAll(resp.Body)
	if err != nil {
		return fmt.Errorf("failed to read install script: %w", err)
	}

	// Write to temporary file
	tmpFile, err := os.CreateTemp("", "ddx-install-*.sh")
	if err != nil {
		return fmt.Errorf("failed to create temp file: %w", err)
	}
	defer func() { _ = os.Remove(tmpFile.Name()) }()

	if _, err := tmpFile.Write(scriptContent); err != nil {
		_ = tmpFile.Close()
		return fmt.Errorf("failed to write install script: %w", err)
	}

	if err := tmpFile.Chmod(0755); err != nil {
		_ = tmpFile.Close()
		return fmt.Errorf("failed to make script executable: %w", err)
	}
	_ = tmpFile.Close()

	// Execute install script
	cmd := exec.Command("bash", tmpFile.Name())
	cmd.Stdout = out
	cmd.Stderr = out
	cmd.Stdin = os.Stdin

	if err := cmd.Run(); err != nil {
		return fmt.Errorf("install script failed: %w", err)
	}

	return nil
}

package cmd

import (
	"fmt"
	"io"
	"os"
